"use strict";const Ajv=require("ajv"),fastJsonStringify=require("fast-json-stringify");function ValidatorSelector(){const t=new Map,e=new Map;return e.put=e.set,function(r,i){const o=`${JSON.stringify(r)}${JSON.stringify(i.customOptions)}`;if(t.has(o))return t.get(o);const n=ValidatorCompiler(r,i,e);return t.set(o,n),n}}function ValidatorCompiler(t,e,r){const i=new Ajv(Object.assign({coerceTypes:!0,useDefaults:!0,removeAdditional:!0,allErrors:!1,nullable:!0},e.customOptions,{cache:r}));if(e.plugins&&e.plugins.length>0)for(const t of e.plugins)t[0](i,t[1]);const o=Object.values(t);for(const t of o)i.addSchema(t);return function({schema:t,method:e,url:r,httpPart:o}){if(t.$id){const e=i.getSchema(t.$id);if(e)return e}return i.compile(t)}}function SerializerCompiler(t){return function({schema:e,method:r,url:i,httpStatus:o}){return fastJsonStringify(e,{schema:t})}}module.exports.ValidatorSelector=ValidatorSelector,module.exports.SerializerCompiler=SerializerCompiler;